INSERT INTO content (page, section, title, content, image_path) VALUES ('about', 'lycee_s_t_alexandre_sauli_de_muhura_peres_barnabites', 'Lycee S t Alexandre Sauli De Muhura Peres Barnabites', 'Home About Academic Staff Events Announcements Departments Fashion Design (FAD) Accounting ICT Software Development (SOD) Computer Systems & Architecture (CSA) Networking & Internet Technology (NIT) Contact Login Login', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('about', 'who_we_are', 'Who We Are', 'Lycee Saint Alexandre Sauli de Muhura is a Catholic secondary school located in the Eastern Province of Rwanda, founded under the spiritual guidance of the Barnabite Fathers . We provide a balanced education integrating academic excellence, Christian morals, discipline, and practical skills. Our learning environment encourages students to grow intellectually, spiritually, creatively, and socially, forming responsible citizens equipped for today’s world.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('about', 'our_mission', 'Our Mission', 'To provide quality education rooted in Christian values, empowering students to become disciplined, skilled, and responsible leaders.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('about', 'our_vision', 'Our Vision', 'To be a leading educational institution nurturing integrity, innovation, academic excellence, and service to God and society.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('about', 'core_values', 'Core Values', 'Respect & Discipline Integrity Excellence Faith & Service Teamwork', NULL);
