INSERT INTO content (page, section, title, content, image_path) VALUES ('about', 'acc', 'ACC', 'Accounting & Business Management', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('about', 'who_was_saint_alexandre_sauli', 'Who Was Saint Alexandre Sauli?', 'Saint Alexandre Sauli (1534–1592) was a Barnabite priest, bishop, and scholar, known as the "Apostle of Corsica" . He dedicated his life to education, peacebuilding, and spiritual guidance. Sauli studied in Milan and became a prominent figure in church reform. He was appointed Bishop of Aleria, Corsica, where he worked tirelessly to educate clergy and laity alike. His writings emphasized moral integrity, leadership, and devotion to God. Sauli''s humility and dedication to youth education inspired the identity and mission of our school. Today, Lycee Saint Alexandre Sauli de Muhura embodies his vision by integrating faith, discipline, and knowledge, preparing students for a life of service, responsibility, and excellence. Read More About Sauli', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('about', 'the_barnabite_fathers', 'The Barnabite Fathers', 'The Barnabites (Clerics Regular of St. Paul) were founded in 1530 by St. Anthony Maria Zaccaria. Their mission includes youth education, pastoral care, moral guidance, and community service. Lycee Saint Alexandre Sauli de Muhura is proudly guided by Barnabite principles of faith, charity, humility, and intellectual formation.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('about', 'why_choose_our_school', 'Why Choose Our School?', 'Qualified Teachers Strong Moral Foundation Modern Learning Facilities Practical & Technical Skills', NULL);
