INSERT INTO content (page, section, title, content, image_path) VALUES ('academic', 'fashion_design', 'Fashion Design', 'Students learn creative design, pattern making, and garment construction. Emphasis on discipline, craftsmanship, teamwork, and ethical practices inspired by Catholic values.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('academic', 'ict', 'ICT', 'Includes Software Development, Computer System & Architecture, and Networking. Focus on critical thinking, problem-solving, and modern technology skills, combined with discipline and integrity.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('academic', 'accounting', 'Accounting', 'Students learn bookkeeping, financial management, and business ethics. Discipline, organization, and accuracy are emphasized, aligned with our Barnabite guidance.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('academic', 'nesa_chronograms', 'NESA Chronograms', 'Click below to view the official NESA academic schedules directly on this page. Term 1 Chronogram "> Term 1 View the detailed schedule for Term 1. Term 2 Chronogram "> Term 2 View the detailed schedule for Term 2. Term 3 Chronogram "> Term 3 View the detailed schedule for Term 3.', NULL);
