INSERT INTO content (page, section, title, content, image_path) VALUES ('acc', 'senior_4_fundamentals_of_accounting_2', 'Senior 4 - Fundamentals of Accounting', 'Introduction to accounting principles Single-entry bookkeeping Preparation of basic financial statements Understanding assets, liabilities, and equity View/Download Senior 4 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('acc', 'senior_5_advanced_accounting_2', 'Senior 5 - Advanced Accounting', 'Double-entry bookkeeping Ledger preparation and trial balance Income statement and balance sheet preparation Financial analysis and interpretation View/Download Senior 5 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('acc', 'senior_6_accounting_applications_projects_2', 'Senior 6 - Accounting Applications & Projects', 'Financial reporting and auditing basics Introduction to taxation and payroll accounting Practical accounting projects and case studies Preparation for higher education or professional certifications View/Download Senior 6 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('acc', 'about_accounting_program', 'About Accounting Program', 'The Accounting program at Lycee de Muhura develops students’ expertise in bookkeeping, financial reporting, and business management. Senior 4 introduces basic concepts, Senior 5 focuses on advanced accounting, and Senior 6 emphasizes applications and projects, preparing students for professional careers in finance and accounting. All departments', NULL);
