INSERT INTO content (page, section, title, content, image_path) VALUES ('anouncement', 'new_academic_curriculum_2025', 'New Academic Curriculum 2025', 'We are excited to announce the updated curriculum for the next academic year. It includes enhanced ICT programs, modern teaching methods, and skill-based learning opportunities for students. Read More', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('anouncement', 'scholarship_opportunities', 'Scholarship Opportunities', 'Lycee de Muhura proudly introduces new scholarship programs for outstanding students. Apply before the deadline to secure funding for your education and skill development. Read More', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('anouncement', 'ict_workshop_for_students', 'ICT Workshop for Students', 'A week-long ICT workshop will be conducted to enhance practical skills in software development, networking, and system architecture. Open for all students interested in technology. Read More', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('anouncement', 'annual_science_fair', 'Annual Science Fair', 'Our Annual Science Fair will showcase innovative projects from students across all departments. Join us to explore cutting-edge experiments, inventions, and creative learning ideas. Read More', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('anouncement', 'fashion_design_showcase', 'Fashion Design Showcase', 'Our Fashion Design students will present their latest creations in a public showcase. Witness creativity, innovation, and professional craftsmanship in the world of fashion. Read More', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('anouncement', 'parent_teacher_meeting', 'Parent-Teacher Meeting', 'Scheduled for next month, this meeting allows parents to engage directly with teachers about student progress, curriculum updates, and strategies to improve learning outcomes. Read More', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('anouncement', 'library_expansion', 'Library Expansion', 'Our school library has expanded with new books, digital resources, and study zones. Students can now access more learning material than ever before for academic excellence. Read More', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('anouncement', 'upcoming_sports_events', 'Upcoming Sports Events', 'Prepare for an exciting series of inter-school sports competitions. Lycee de Muhura encourages students to participate and showcase their athletic skills. Read More', NULL);
