INSERT INTO content (page, section, title, content, image_path) VALUES ('contact', 'we_value_communication_and_are_always_ready_to_assist_students_parents_and_visitors_whether_you_have_questions_about_our_programs_admissions_events_or_any_other_inquiries_our_team_is_here_to_provide_the_information_you_need', 'We value communication and are always ready to assist students, parents, and visitors. Whether you have questions about our programs, admissions, events, or any other inquiries, our team is here to provide the information you need.', 'Feel free to reach out via phone, email, or by visiting our campus. Your feedback and suggestions are important to us, and we strive to respond promptly and efficiently. Connect with Lycee de Muhura and let us help you take the next step in your educational journey.', NULL);
