INSERT INTO content (page, section, title, content, image_path) VALUES ('csa', 'introduction_to_computer_architecture', 'Introduction to Computer Architecture', 'Understand basic hardware components, CPU architecture, and data representation. Level 3', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('csa', 'operating_systems', 'Operating Systems', 'Learn OS fundamentals, process management, memory management, and file systems. Level 4', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('csa', 'hardware_peripherals', 'Hardware & Peripherals', 'Study storage devices, input/output systems, buses, and peripheral integration. Level 5', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('csa', 'embedded_systems', 'Embedded Systems', 'Explore microcontrollers, sensors, and building simple embedded applications. Level 4', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('csa', 'networked_systems', 'Networked Systems', 'Learn system interconnects, networking basics, and distributed system concepts. Level 5', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('csa', 'capstone_project', 'Capstone Project', 'Apply knowledge to assemble and optimize a complete computer system setup. Level 3', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('csa', 'level_3_introduction_to_computer_architecture', 'Level 3 - Introduction to Computer Architecture', 'Basic computer components: CPU, memory, I/O devices Binary and data representation Simple assembly language introduction Mini-project: Assemble a basic computer model View/Download Level 3 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('csa', 'level_4_operating_systems_embedded_systems', 'Level 4 - Operating Systems & Embedded Systems', 'Operating system fundamentals Process scheduling and memory management Introduction to embedded systems and microcontrollers Hardware-software interfacing View/Download Level 4 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('csa', 'level_5_advanced_systems_capstone_project', 'Level 5 - Advanced Systems & Capstone Project', 'Advanced CPU and memory system design Networked systems and distributed computing Embedded systems project development Capstone: Build and optimize a complete computer system Preparation for higher education or IT industry View/Download Level 5 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('csa', 'about_computer_systems_architecture_program', 'About Computer Systems & Architecture Program', 'The CSA program at Lycee de Muhura teaches students how computers work from the ground up. From basic hardware assembly to advanced operating system concepts and embedded systems, students acquire skills to design, analyze, and optimize computer systems for both industry and research applications. All departments', NULL);
