INSERT INTO content (page, section, title, content, image_path) VALUES ('fad', 'level_4_pattern_making_textiles', 'Level 4 - Pattern Making & Textiles', 'Advanced sewing techniques and garment construction Pattern making for different clothing types Textile selection and fabric handling View/Download Level 2 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('fad', 'level_5_fashion_illustration_accessories', 'Level 5 - Fashion Illustration & Accessories', 'Fashion sketching and portfolio development Accessory design: bags, shoes, jewelry Costume and creative project development View/Download Level 3 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('fad', 'about_fashion_design_program', 'About Fashion Design Program', 'The Fashion Design program at Lycee de Muhura equips students with creativity and technical skills to excel in the fashion industry. From learning sewing and pattern making to developing fashion collections, students gain hands-on experience to pursue careers as designers, stylists, or entrepreneurs in apparel and accessories. All departments', NULL);
