INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'who_we_are', 'Who We Are', 'Lycee Saint Alexandre Sauli de Muhura is dedicated to forming students academically, spiritually, and morally. Through the guidance of the Barnabite Fathers, we emphasize discipline, excellence, hard work, and Christian values. Strong discipline and character formation. High-quality technical and vocational training. Catholic education rooted in moral and spiritual values. Read More', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'why_choose_our_school', 'Why Choose Our School?', 'We combine academic excellence, hands-on technical training, and moral formation. Students graduate with solid professional skills and a deep sense of responsibility, leadership, and Christian values. Learn More', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'technical_excellence', 'Technical Excellence', 'Quality training in ICT, Fashion Design, and Accounting.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'discipline_integrity', 'Discipline & Integrity', 'We mold students into confident, disciplined, and responsible citizens.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'faith_moral_formation', 'Faith & Moral Formation', 'Daily spiritual guidance from Barnabite Fathers.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'programs', 'Programs', 'Our Technical Courses ICT', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'software_development', 'Software Development', 'Software is a collection of programs and instructions that enable a computer to perform specific tasks. It includes system software, which manages the hardware and provides a platform for other programs, and application software, which helps users complete tasks like writing documents, browsing the internet, or playing games. Software is essential because it gives functionality to the computer hardware. ICT', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'networking_and_internet_technology', 'Networking and Internet Technology', 'Networking connects computers and devices to share data and resources. The Internet is a global network enabling communication, information access, and online services. Modern technology, including cloud computing, IoT, and AI, relies on these networks to connect people and devices worldwide. ICT', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'computer_system_and_architecture', 'Computer System and Architecture', 'A computer system is a combination of hardware and software that processes, stores, and outputs data. Computer architecture refers to how a computer’s components—CPU, memory, input/output devices, and storage—are organized and interact to perform tasks efficiently. It determines the speed, capability, and functionality of a computer. Fashion & Design', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'fashion_design', 'Fashion Design', 'Fashion Design is the art and practice of creating clothing, accessories, and footwear that are both functional and aesthetically appealing. It combines creativity, style, and technical skills to produce garments that reflect trends, culture, and individual expression. Fashion designers consider fabrics, colors, patterns, and silhouettes to bring their ideas to life. Our Proffesional Course Business', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'accounting', 'Accounting', 'Accounting is the systematic process of recording, summarizing, and analyzing financial transactions of a business or organization. It provides essential information about income, expenses, assets, and liabilities, helping stakeholders make informed financial decisions. Accounting ensures transparency, accuracy, and proper management of resources.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'barnabite_fathers', 'Barnabite Fathers', 'School Leadership Providing spiritual, moral, and institutional guidance.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'ict_instructors', 'ICT Instructors', 'Technical Trainers Specialists in SOD, CSA, and NIT programs.', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('index', 'vocational_trainers', 'Vocational Trainers', 'FAD & Accounting Professionals preparing students for productive careers.', NULL);
