INSERT INTO content (page, section, title, content, image_path) VALUES ('nit', 'networking_fundamentals', 'Networking Fundamentals', 'Learn about network types, topologies, protocols, and basic configuration. Level 3', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('nit', 'lan_wan_technologies', 'LAN & WAN Technologies', 'Study local and wide area networks, switches, routers, and IP addressing. Level 4', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('nit', 'network_security', 'Network Security', 'Implement firewall rules, VPNs, encryption, and secure communication protocols. Level 5', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('nit', 'internet_technologies', 'Internet Technologies', 'Learn about DNS, HTTP/HTTPS, cloud networking, and network troubleshooting. Level 4', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('nit', 'wireless_mobile_networks', 'Wireless & Mobile Networks', 'Study Wi-Fi, mobile network standards, and IoT device connectivity. Level 5', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('nit', 'capstone_project', 'Capstone Project', 'Design and configure a secure network for a simulated organization. Level 3', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('nit', 'level_3_networking_fundamentals', 'Level 3 - Networking Fundamentals', 'Introduction to networks: LAN, WAN, and topologies OSI and TCP/IP models IP addressing and subnetting basics Capstone mini-project: Set up a simple LAN View/Download Level 3 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('nit', 'level_4_lan_wan_internet_technologies', 'Level 4 - LAN, WAN & Internet Technologies', 'Router & switch configuration DHCP, DNS, and IP routing Introduction to cloud networking Basic network troubleshooting and monitoring View/Download Level 4 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('nit', 'level_5_advanced_networking_security', 'Level 5 - Advanced Networking & Security', 'Network security: firewalls, VPNs, and encryption Wireless network configuration (Wi-Fi & IoT) Advanced troubleshooting and performance optimization Capstone project: Design a secure network for a medium-sized organization Preparation for professional certifications (e.g., CCNA) View/Download Level 5 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('nit', 'about_networking_internet_technology_program', 'About Networking & Internet Technology Program', 'The Networking & Internet Technology program at Lycee de Muhura provides a structured learning path from foundational networking concepts to advanced security and cloud technologies. Students gain practical skills configuring networks, troubleshooting issues, and securing communication systems. Graduates are prepared for IT careers or higher studies in networking and cybersecurity. All departments', NULL);
