INSERT INTO content (page, section, title, content, image_path) VALUES ('sod', 'introduction_to_programming', 'Introduction to Programming', 'Learn Python and Java basics, including syntax, loops, and functions. Level 3', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('sod', 'web_development', 'Web Development', 'HTML, CSS, and JavaScript to create interactive and responsive web applications. Level 4', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('sod', 'database_management', 'Database Management', 'SQL and database design for storing and retrieving application data efficiently. Level 5', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('sod', 'software_engineering', 'Software Engineering', 'Learn methodologies like Agile, version control, and software lifecycle practices. Level 4', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('sod', 'mobile_app_development', 'Mobile App Development', 'Create functional mobile apps for Android and iOS platforms. Level 5', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('sod', 'capstone_project', 'Capstone Project', 'Apply all learned skills to develop a real-world software solution. Level 3', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('sod', 'level_3_introduction_to_programming', 'Level 3 - Introduction to Programming', 'Python basics: variables, loops, functions Java fundamentals: syntax, data types, control structures Basic problem-solving and debugging Capstone mini-project: Build a simple calculator View/Download Level 3 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('sod', 'level_4_web_software_development', 'Level 4 - Web & Software Development', 'HTML, CSS, and JavaScript for web design Responsive web development using Bootstrap Introduction to software engineering principles Version control using Git and GitHub Agile project management basics View/Download Level 4 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('sod', 'level_5_advanced_development_projects', 'Level 5 - Advanced Development & Projects', 'Advanced database design and SQL queries Mobile app development for Android & iOS Capstone project: Develop a complete software solution Performance optimization and debugging Preparation for industry deployment or higher education View/Download Level 5 NESA Chronogram', NULL);
INSERT INTO content (page, section, title, content, image_path) VALUES ('sod', 'about_software_development_program', 'About Software Development Program', 'The Software Development program at Lycee de Muhura provides a progressive learning path through levels 3 to 5. Students develop problem-solving skills, gain practical programming experience, and build real-world applications. Our curriculum ensures that graduates are ready to join the tech industry or continue higher studies with confidence. All departments', NULL);
